4	const IRC_TARGET_PATTERN = /^[^\s:]+$/u;
5	
6	export function isChannelTarget(target: string): boolean {
7	  return target.startsWith("#") || target.startsWith("&");
8	}
9	
10	export function normalizeIrcMessagingTarget(raw: string): string | undefined {
11	  const trimmed = raw.trim();
12	  if (!trimmed) {
13	    return undefined;
14	  }
15	  let target = trimmed;
16	  const lowered = target.toLowerCase();
17	  if (lowered.startsWith("irc:")) {
18	    target = target.slice("irc:".length).trim();
19	  }
20	  if (target.toLowerCase().startsWith("channel:")) {
21	    target = target.slice("channel:".length).trim();
22	    if (!target.startsWith("#") && !target.startsWith("&")) {
23	      target = `#${target}`;
24	    }
25	  }
26	  if (target.toLowerCase().startsWith("user:")) {
27	    target = target.slice("user:".length).trim();
28	  }
29	  if (!target || !looksLikeIrcTargetId(target)) {
30	    return undefined;
31	  }
32	  return target;
33	}
34	
35	export function looksLikeIrcTargetId(raw: string): boolean {
36	  const trimmed = raw.trim();
37	  if (!trimmed) {
38	    return false;
39	  }
40	  if (hasIrcControlChars(trimmed)) {
41	    return false;
42	  }
43	  return IRC_TARGET_PATTERN.test(trimmed);
44	}
45	
46	export function normalizeIrcAllowEntry(raw: string): string {
47	  let value = raw.trim().toLowerCase();
48	  if (!value) {
49	    return "";
50	  }
51	  if (value.startsWith("irc:")) {
52	    value = value.slice("irc:".length);
53	  }
54	  if (value.startsWith("user:")) {
55	    value = value.slice("user:".length);
56	  }
57	  return value.trim();
58	}
59	
60	export function normalizeIrcAllowlist(entries?: Array<string | number>): string[] {
61	  return (entries ?? []).map((entry) => normalizeIrcAllowEntry(String(entry))).filter(Boolean);
62	}
63	
64	export function formatIrcSenderId(message: IrcInboundMessage): string {
65	  const base = message.senderNick.trim();
66	  const user = message.senderUser?.trim();
67	  const host = message.senderHost?.trim();
68	  if (user && host) {
69	    return `${base}!${user}@${host}`;
70	  }
71	  if (user) {
72	    return `${base}!${user}`;
73	  }
74	  if (host) {
75	    return `${base}@${host}`;
76	  }
77	  return base;
78	}
79	
80	export function buildIrcAllowlistCandidates(
81	  message: IrcInboundMessage,
82	  params?: { allowNameMatching?: boolean },
83	): string[] {
84	  const nick = message.senderNick.trim().toLowerCase();
85	  const user = message.senderUser?.trim().toLowerCase();
86	  const host = message.senderHost?.trim().toLowerCase();
87	  const candidates = new Set<string>();
88	  if (nick && params?.allowNameMatching === true) {
89	    candidates.add(nick);
90	  }
91	  if (nick && user) {
92	    candidates.add(`${nick}!${user}`);
93	  }
94	  if (nick && host) {
95	    candidates.add(`${nick}@${host}`);
96	  }
97	  if (nick && user && host) {
98	    candidates.add(`${nick}!${user}@${host}`);
99	  }
100	  return [...candidates];
101	}
102	
103	export function resolveIrcAllowlistMatch(params: {
104	  allowFrom: string[];
105	  message: IrcInboundMessage;
106	  allowNameMatching?: boolean;
107	}): { allowed: boolean; source?: string } {
108	  const allowFrom = new Set(
109	    params.allowFrom.map((entry) => entry.trim().toLowerCase()).filter(Boolean),
110	  );
111	  if (allowFrom.has("*")) {
112	    return { allowed: true, source: "wildcard" };
113	  }
114	  const candidates = buildIrcAllowlistCandidates(params.message, {
115	    allowNameMatching: params.allowNameMatching,
116	  });
117	  for (const candidate of candidates) {
118	    if (allowFrom.has(candidate)) {
119	      return { allowed: true, source: candidate };
120	    }
121	  }
122	  return { allowed: false };
123	}
