import type {
  BaseProbeResult,
  BlockStreamingCoalesceConfig,
  DmPolicy,
  GroupPolicy,
  MarkdownConfig,
  OpenClawConfig,
} from "./runtime-api.js";

export type PulseboardBoardConfig = {
  requireMention?: boolean;
  enabled?: boolean;
  allowFrom?: Array<string | number>;
  systemPrompt?: string;
};

export type PulseboardAccountConfig = {
  /** Optional display name for this account (used in CLI/UI lists). */
  name?: string;
  /** If false, do not start this PulseBoard account. Default: true. */
  enabled?: boolean;
  /** API token for authenticating with the PulseBoard server. */
  apiToken?: string;
  /** Base URL of the PulseBoard server (e.g. https://pb.example.com). */
  serverUrl?: string;
  /** Direct message policy (pairing/allowlist/open/disabled). */
  dmPolicy?: DmPolicy;
  /** Allowlist for direct messages (usernames). */
  allowFrom?: Array<string | number>;
  /** Group message policy (allowlist/open/disabled). */
  groupPolicy?: GroupPolicy;
  /** Allowlist for board (group) messages (usernames). */
  groupAllowFrom?: Array<string | number>;
  /**
   * Per-board configuration keyed by board name (e.g. "#announcements").
   * Use "*" as a wildcard for all boards not explicitly listed.
   */
  boards?: Record<string, PulseboardBoardConfig>;
  /** Markdown rendering config for outbound messages. */
  markdown?: MarkdownConfig;
  /** Outbound text chunk size (chars). Default: 4000. */
  textChunkLimit?: number;
  /** Disable block streaming for this account. */
  blockStreaming?: boolean;
  /** Merge streamed block replies before sending. */
  blockStreamingCoalesce?: BlockStreamingCoalesceConfig;
  /** Default target for outbound messages when none is specified. */
  defaultTo?: string;
  /** Outbound response prefix override for this account. */
  responsePrefix?: string;
};

export type PulseboardConfig = PulseboardAccountConfig & {
  /** Per-account overrides keyed by account id. */
  accounts?: Record<string, PulseboardAccountConfig>;
  /** Default account id when multiple accounts are configured. */
  defaultAccount?: string;
};

export type CoreConfig = OpenClawConfig & {
  channels?: OpenClawConfig["channels"] & {
    pulseboard?: PulseboardConfig;
  };
};

export type PulseboardInboundMessage = {
  messageId: string;
  /** Board name for group messages (e.g. "#dev"), sender username for DMs. */
  target: string;
  senderUsername: string;
  senderDisplayName?: string;
  text: string;
  timestamp: number;
  isGroup: boolean;
};

export type PulseboardProbe = BaseProbeResult<string> & {
  serverUrl: string;
  latencyMs?: number;
};

