import { resolvePulseboardAccount } from "./accounts.js";
import { normalizePulseboardMessagingTarget } from "./normalize.js";
import { getPulseboardRuntime } from "./runtime.js";
import type { CoreConfig } from "./types.js";

export type SendPulseboardOptions = {
  cfg?: CoreConfig;
  accountId?: string;
  replyTo?: string;
};

export type SendPulseboardResult = {
  messageId: string;
  target: string;
};

function recordPulseboardOutboundActivity(accountId: string): void {
  try {
    getPulseboardRuntime().channel.activity.record({
      channel: "pulseboard",
      accountId,
      direction: "outbound",
    });
  } catch (error) {
    if (
      !(error instanceof Error) ||
      error.message !== "PulseBoard runtime not initialized"
    ) {
      throw error;
    }
  }
}

function resolveTarget(to: string): string {
  const normalized = normalizePulseboardMessagingTarget(to);
  if (normalized) {
    return normalized;
  }
  throw new Error(`Invalid PulseBoard target: ${to}`);
}

/**
 * Send a message to a PulseBoard board or user via the PulseBoard REST API.
 *
 * POST /api/v1/messages
 * Body: { target, text, replyTo? }
 * Auth: Bearer <apiToken>
 */
export async function sendMessagePulseboard(
  to: string,
  text: string,
  opts: SendPulseboardOptions = {},
): Promise<SendPulseboardResult> {
  const runtime = getPulseboardRuntime();
  const cfg = (opts.cfg ?? runtime.config.loadConfig()) as CoreConfig;
  const account = resolvePulseboardAccount({
    cfg,
    accountId: opts.accountId,
  });

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" (need apiToken and serverUrl in channels.pulseboard).`,
    );
  }

  const target = resolveTarget(to);
  const payload = opts.replyTo ? `${text.trim()}\n\n[reply:${opts.replyTo}]` : text.trim();

  if (!payload) {
    throw new Error("Message must be non-empty for PulseBoard sends");
  }

  const url = `${account.serverUrl.replace(/\/$/, "")}/api/v1/messages`;
  const body: Record<string, string> = { target, text: payload };
  if (opts.replyTo) {
    body.replyTo = opts.replyTo;
  }

  const response = await fetch(url, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${account.apiToken}`,
    },
    body: JSON.stringify(body),
  });

  if (!response.ok) {
    throw new Error(
      `PulseBoard send failed: HTTP ${response.status} ${response.statusText}`,
    );
  }

  const data = (await response.json()) as { messageId?: string };
  const messageId = data.messageId ?? `pb-${Date.now()}`;

  recordPulseboardOutboundActivity(account.accountId);

  return { messageId, target };
}

