function formatError(err: unknown): string {
  if (err instanceof Error) {
    return err.message;
  }
  return typeof err === "string" ? err : JSON.stringify(err);
}

/**
 * Probe the PulseBoard server by hitting GET /api/v1/ping with the configured API token.
 * Returns a PulseboardProbe indicating connectivity and latency.
