import { resolveLoggerBackedRuntime } from "openclaw/plugin-sdk/extension-shared";
import { resolvePulseboardAccount } from "./accounts.js";
import { handlePulseboardInbound } from "./inbound.js";
import type { RuntimeEnv } from "./runtime-api.js";
import { getPulseboardRuntime } from "./runtime.js";
import type { CoreConfig, PulseboardInboundMessage } from "./types.js";

export type PulseboardMonitorOptions = {
  accountId?: string;
  config?: CoreConfig;
  runtime?: RuntimeEnv;
  abortSignal?: AbortSignal;
  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
  onMessage?: (message: PulseboardInboundMessage) => void | Promise<void>;
};

/**
 * Poll the PulseBoard server for new inbound messages using long-polling.
 *
 * GET /api/v1/messages/poll
 * Headers: Authorization: Bearer <apiToken>
 * Query:   ?since=<lastSeenId>
 *
 * Returns an object with a `stop()` method.
 */
export async function monitorPulseboardProvider(
  opts: PulseboardMonitorOptions,
): Promise<{ stop: () => void }> {
  const core = getPulseboardRuntime();
  const cfg = opts.config ?? (core.config.loadConfig() as CoreConfig);
  const account = resolvePulseboardAccount({ cfg, accountId: opts.accountId });

  const runtime: RuntimeEnv = resolveLoggerBackedRuntime(
    opts.runtime,
    core.logging.getChildLogger(),
  );

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" (need apiToken and serverUrl in channels.pulseboard).`,
    );
  }

  const logger = core.logging.getChildLogger({
    channel: "pulseboard",
    accountId: account.accountId,
  });

  logger.info(
    `[${account.accountId}] starting PulseBoard monitor (${account.serverUrl})`,
  );

  let stopped = false;
  let lastMessageId: string | undefined;

  const pollOnce = async (): Promise<void> => {
    const url = new URL(
      `${account.serverUrl.replace(/\/$/, "")}/api/v1/messages/poll`,
    );
    if (lastMessageId) {
      url.searchParams.set("since", lastMessageId);
    }

    const response = await fetch(url.toString(), {
      method: "GET",
      headers: { Authorization: `Bearer ${account.apiToken}` },
      signal: opts.abortSignal,
    });

    if (!response.ok) {
      logger.error(
        `[${account.accountId}] poll failed: HTTP ${response.status} ${response.statusText}`,
      );
      return;
    }

    const data = (await response.json()) as {
      messages?: Array<{
        id: string;
        target: string;
        senderUsername: string;
        senderDisplayName?: string;
        text: string;
        timestamp: number;
        isGroup: boolean;
      }>;
    };

    for (const item of data.messages ?? []) {
      lastMessageId = item.id;

      const message: PulseboardInboundMessage = {
        messageId: item.id,
        target: item.target,
        senderUsername: item.senderUsername,
        senderDisplayName: item.senderDisplayName,
        text: item.text,
        timestamp: item.timestamp,
        isGroup: item.isGroup,
      };

      core.channel.activity.record({
        channel: "pulseboard",
        accountId: account.accountId,
        direction: "inbound",
        at: message.timestamp,
      });

      if (opts.onMessage) {
        await opts.onMessage(message);
        continue;
      }

      await handlePulseboardInbound({
        message,
        account,
        config: cfg,
        runtime,
        statusSink: opts.statusSink,
      });
    }
  };

  const loop = async (): Promise<void> => {
    while (!stopped && !(opts.abortSignal?.aborted)) {
      try {
        await pollOnce();
      } catch (err) {
        if (opts.abortSignal?.aborted) {
          break;
        }
        logger.error(`[${account.accountId}] poll error: ${String(err)}`);
        // Back off briefly before retrying.
        await new Promise<void>((resolve) => setTimeout(resolve, 5000));
      }
    }
  };

  // Start the poll loop in the background; it resolves when stopped/aborted.
  const loopDone = loop();

  return {
    stop: () => {
      stopped = true;
      // Await the loop finishing is handled by the caller via abortSignal.
      void loopDone;
    },
  };
}

